mapper.select:
SELECT  FROM fld_visit
WHERE tenant_id = #{tenantId} AND work_order_id = #{workOrderId}
ORDER BY check_in_captured_at, visit_id

SELECT version FROM tsk_task
WHERE tenant_id = #{tenantId} AND task_id = #{taskId}
FOR UPDATE

SELECT visit_id AS "visitId", status, aggregate_version AS "aggregateVersion",
       geofence_result AS "geofenceResult", policy_decision AS "policyDecision",
       occurred_at AS "occurredAt"
FROM fld_visit_command_result
WHERE tenant_id = #{tenantId} AND operation_type = #{operationType}
  AND idempotency_key = #{idempotencyKey}
